from pathlib import Path

logs_path = Path(GetVar("LOGS_PATH"))
error_path = logs_path / "Error"
info_path = logs_path / "Info"
img_path = error_path / "img"
error_log_file = error_path / "logs.txt"
info_log_file = info_path / "logs.txt"

if not logs_path.exists():
	logs_path.mkdir(parents=True)
if not error_path.exists():
  	error_path.mkdir()
if not info_path.exists():
  	info_path.mkdir() 
if not img_path.exists():
  	img_path.mkdir()
if not error_log_file.exists():
  	error_log_file.touch()
if not info_log_file.exists():
  	info_log_file.touch()

from pathlib import Path

scripts_path = Path(GetVar("SCRIPTS_PATH"))
scripts = {GetVar("script_wo_parser"), GetVar("script_wo_loader")}

existing_scripts = {f.name for f in scripts_path.iterdir() if f.is_file()}
missing_scripts = scripts - existing_scripts

SetVar("missing_scripts", missing_scripts)

project_path = Path(GetVar("PROJECT_PATH"))
config_path = project_path / "config"
env = GetVar("ENV")
configs = {f"{env}.json"}

if not config_path.exists():
  	config_path.mkdir()

existing_configs = {f.name for f in config_path.iterdir() if f.is_file()}
missing_configs = configs - existing_configs

SetVar("missing_configs", missing_configs)
